import React from 'react'
import './Profile.css'
import {useState,useEffect} from 'react'
const Profile = ({usr}) => {

    //user=>bio,location,imageUrl,

    const [userDetails,setUserDetails]=useState()
    const [user, setUser] = useState({
        name: "John Doe",
        email: "john.doe@example.com",
        phone: "+1 234 567 890",
        bio: "I am a software developer with expertise in React and Node.js. I love building beautiful and functional web applications.",
        profilePicture: "https://via.placeholder.com/150", // Placeholder image
        location: "San Francisco, CA",
      });
    
      const handleEdit = () => {
        // const newName = prompt("Enter new name:", userDetails.name);
        const newEmail = prompt("Enter new email:", userDetails.email);
        const newPhone = prompt("Enter new phone:", userDetails.phone);
        const newBio = prompt("Enter new bio:", userDetails.bio);
        const newLocation = prompt("Enter new location:", userDetails.location);
    
        setUser({
          ...userDetails,
          email: newEmail || userDetails.email,
          phone: newPhone || userDetails.phone,
          bio: newBio || userDetails.bio,
          location: newLocation || userDetails.location,
        });
      };
    
      const handleProfilePictureChange = () => {
        const newPicture = prompt(
          "Enter new profile picture URL:",
          user.profilePicture
        );
        setUserDetails({
          ...userDetails,
          image: newPicture || user.profilePicture,
        });
      };
      const fetchUser=async()=>{
        const username_fetchuser=localStorage.getItem('username')
        const response=await fetch(`${process.env.REACT_APP_BASE_URL}/userinfo`,{
            method:"POST",
            headers:{'Content-Type': 'application/json'},
            body:JSON.stringify({username_fetchuser}),
            credentials: 'include'
          })
          const data=await response.json()
          console.log(data)
          setUserDetails(data)
      }
      useEffect(()=>{
        fetchUser()
      },[])
  return (
    <div className="profile-main">
      {(userDetails&& usr)&&
      <div className="profile-container">
      <div className="profile-card">
        <img
          src=""
          alt="Profile"
          className="profile-image"
          onClick={handleProfilePictureChange}
          title="Click to change profile picture"
        />
        <h2 className="profile-name">{usr.username}</h2>
        <p className="profile-email">{userDetails.email}</p>
        <p className="profile-phone">{userDetails.contactNo}</p>
        <p className="profile-location">{userDetails.location}</p> 
        <p className="profile-bio">{userDetails.bio}</p>
        <button className="edit-profile-button" onClick={handleEdit}>
          Edit Profile
        </button>
      </div>
    </div>
}
    </div>
  )
}

export default Profile
